configuration.jsScript:
var message = []; // create a new message to incorporate
/* define constants of threshold to verify if a data is correct */
const MINTEMPERATURETHRESHOLD = -20; // °C
const MAXTEMPERATURETHRESHOLD = 70;
const MINWEIGHTTHRESHOLD = 0; // kg
const MAXWEIGHTTHRESHOLD = 30;
const MINHUMIDITYTHRESHOLD = 0; // %
const MAXHUMIDITYTHRESHOLD = 100;
const MINNOISETHRESHOLD = 0; // Hz
const MAXNOISETHRESHOLD = 500;

/* for each message check
if it's over the threshold so as to eliminate it */
var check; // create a boolean variable
for(const singleMeasure of msg){
    check = true;

    if("temperature" in singleMeasure && (singleMeasure.temperature<MINTEMPERATURETHRESHOLD || singleMeasure.temperature>MAXTEMPERATURETHRESHOLD))
        check = false;
    else if("humidity" in singleMeasure && (singleMeasure.humidity<MINHUMIDITYTHRESHOLD || singleMeasure.humidity>MAXHUMIDITYTHRESHOLD))
        check = false;
    else if("weight" in singleMeasure && (singleMeasure.weight<MINWEIGHTTHRESHOLD || singleMeasure.weight>MAXWEIGHTTHRESHOLD))
        check = false;
    else if("noise" in singleMeasure && (singleMeasure.noise<MINNOISETHRESHOLD || singleMeasure.noise>MAXNOISETHRESHOLD))
        check = false;

    if(check)
        message.push(singleMeasure);
}

return {msg: message, metadata: metadata, msgType: msgType};

/* tolerate if the data is a single object and 
transform it into an array */
var dataArray = Array.isArray(msg) ? msg : [msg];

return {msg: dataArray, metadata: metadata, msgType: msgType};

/* variable definition */
var currentIndex = -1, currentKey, telemetryList, check = true, result = true;

currentKey = Object.keys(msg)[0]; // get the first and only key

/* get the list of telemetries
and find the telemetry that match the timestamp */
if(!(currentKey in metadata))
    check = false;
else{
    telemetryList = JSON.parse(metadata[currentKey]);
    currentIndex = telemetryList.findIndex(singleTelemetry => Number(singleTelemetry.ts) === Number(metadata.ts));   
}

/* control if a telemetry has been found,
otherwise it's not possible to compare it with other telemetries */
if(currentIndex<0)
    check=false;

/* control if the general average 
has been found in the common asset */
if(!("general_"+currentKey in metadata))
    check=false;

/* control if the message is closer to the average, otherwise
it's not possible to replace the telemetry */
if(Math.abs(msg[currentKey] - Number(metadata["general_"+currentKey]))>=Math.abs(Number(telemetryList[currentIndex].value) - Number(metadata["general_"+currentKey])))
    result = false;

/* copy the result to metadata and
return the message */
metadata.valid = result;
metadata.sameTelemetry = currentIndex;

return {msg: msg, metadata: metadata, msgType: msgType};

var result = JSON.parse(metadata.valid); // add this to get the boolean

if(result)
    return ['valid'];

return ['dropped'];

